[obs, LoggedSignals] = resetFunction_nav_CST_Reward_Mixed_deployment(EnvPars);

t_psi_x_dqn_frame = zeros(1,N_Steps);
t_psi_y_dqn_frame = zeros(1,N_Steps);

psi_x_dqn = zeros(1,N_Steps);
